import { BrowserRouter, Routes, Route, Navigate } from "react-router-dom";
import { AuthProvider } from "./AuthContext";
import { PrivateRoute, RoleGuard } from "./routeGuards";
import Layout from "./components/Layout";        // layout có Sidebar + Header
import Login from "./components/Login";
import Dashboard from "./pages/Dashboard";
import Customers from "./pages/Customers";
import Contracts from "./pages/Contracts";
import Payments from "./pages/Payments";
import Users from "./pages/Users";
import Events from "./pages/Events";
import Reports from "./pages/Reports";
import Forbidden from "./pages/Forbidden";
import NotFound from "./pages/NotFound";

export default function App() {
    return (
        <AuthProvider>
            <BrowserRouter>
                <Routes>
                    {/* Public */}
                    <Route path="/login" element={<Login />} />

                    {/* Tất cả route bên dưới đều cần đăng nhập */}
                    <Route
                        path="/"
                        element={
                            <PrivateRoute>
                                <Layout />
                            </PrivateRoute>
                        }
                    >
                        {/* Tổng quan: ai đăng nhập cũng xem được */}
                        <Route
                            index
                            element={
                                <RoleGuard roles={["ADMIN","SALES","ACCOUNTANT"]}>
                                    <Dashboard />
                                </RoleGuard>
                            }
                        />

                        {/* Khách hàng: ADMIN + SALES */}
                        <Route
                            path="customers"
                            element={
                                <RoleGuard roles={["ADMIN","SALES"]}>
                                    <Customers />
                                </RoleGuard>
                            }
                        />

                        {/* Hợp đồng: ADMIN + SALES + ACCOUNTANT (kế toán chỉ xem/không hiện nút tạo/sửa nếu bạn muốn) */}
                        <Route
                            path="contracts"
                            element={
                                <RoleGuard roles={["ADMIN","SALES","ACCOUNTANT"]}>
                                    <Contracts />
                                </RoleGuard>
                            }
                        />

                        {/* Thanh toán: ADMIN + ACCOUNTANT */}
                        <Route
                            path="payments"
                            element={
                                <RoleGuard roles={["ADMIN","ACCOUNTANT"]}>
                                    <Payments />
                                </RoleGuard>
                            }
                        />

                        {/* Sự kiện: ADMIN + SALES */}
                        <Route
                            path="events"
                            element={
                                <RoleGuard roles={["ADMIN","SALES"]}>
                                    <Events />
                                </RoleGuard>
                            }
                        />

                        {/* Người dùng: chỉ ADMIN */}
                        <Route
                            path="users"
                            element={
                                <RoleGuard roles={["ADMIN"]}>
                                    <Users />
                                </RoleGuard>
                            }
                        />

                        {/* Báo cáo: ADMIN + ACCOUNTANT */}
                        <Route
                            path="reports"
                            element={
                                <RoleGuard roles={["ADMIN","ACCOUNTANT"]}>
                                    <Reports />
                                </RoleGuard>
                            }
                        />
                    </Route>

                    <Route path="/403" element={<Forbidden />} />
                    <Route path="*" element={<NotFound />} />
                </Routes>
            </BrowserRouter>
        </AuthProvider>
    );
}
